module watchdog_timer(  
    input wire clk,  
    input wire update,  
    input wire [3:0] timeout,  
    output reg reset  
);  
    reg [3:0] counter;  

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin  
        if (update)  
            counter <= timeout;  
        else if (counter > 0)  
            counter <= counter - 1;  

        reset <= (counter == 0);  
    end  
endmodule
